import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.HG0H2VLS.js";const g=JSON.parse('{"title":"Figma Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"guidelines/workflow.md","filePath":"guidelines/workflow.md"}'),o={name:"guidelines/workflow.md"};function i(l,e,r,p,d,c){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="figma-workflow" tabindex="-1">Figma Workflow <a class="header-anchor" href="#figma-workflow" aria-label="Permalink to &quot;Figma Workflow&quot;">​</a></h1><h1 id="figma-↔-claude-code-workflow-guide" tabindex="-1">Figma ↔ Claude Code Workflow Guide <a class="header-anchor" href="#figma-↔-claude-code-workflow-guide" aria-label="Permalink to &quot;Figma ↔ Claude Code Workflow Guide&quot;">​</a></h1><p>A short reference for the design/dev team on how to use the Figma + Claude Code integration.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FIGMA (design)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  Designer right-clicks component → &quot;Copy link&quot;</span></span>
<span class="line"><span>  │  Shares URL with developer</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>CLAUDE CODE (MCP tools)</span></span>
<span class="line"><span>  ├── get_design_context   → reads layout, spacing, colors from Figma</span></span>
<span class="line"><span>  ├── get_variable_defs    → extracts which --ai-* tokens are applied</span></span>
<span class="line"><span>  └── get_code_connect_map → checks if component already exists in code</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  Generates HTML/CSS using only --ai-* variables</span></span>
<span class="line"><span>  │  (CLAUDE.md enforces zero hardcoded values)</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>CODEBASE (src/components/)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  Developer builds, tests, runs locally</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>FIGMA (via generate_figma_design MCP tool)</span></span>
<span class="line"><span>  └── Built UI pushed back as editable Figma frames</span></span>
<span class="line"><span>      Designer refines → shares updated URL → cycle repeats</span></span></code></pre></div><hr><h2 id="part-1-figma-→-code" tabindex="-1">Part 1: Figma → Code <a class="header-anchor" href="#part-1-figma-→-code" aria-label="Permalink to &quot;Part 1: Figma → Code&quot;">​</a></h2><h3 id="step-1-get-the-figma-node-url" tabindex="-1">Step 1: Get the Figma Node URL <a class="header-anchor" href="#step-1-get-the-figma-node-url" aria-label="Permalink to &quot;Step 1: Get the Figma Node URL&quot;">​</a></h3><ol><li>Open the Figma file</li><li>Click on the component, frame, or element you want to build</li><li>Right-click → <strong>Copy link to selection</strong> (or use ⌘L / Ctrl+L)</li><li>The URL looks like: <code>https://www.figma.com/design/FILEID/File-Name?node-id=123%3A456</code></li></ol><blockquote><p><strong>Tip:</strong> Link to the component itself (in the component library), not an instance on the canvas, for the most accurate variable data.</p></blockquote><h3 id="step-2-use-the-build-component-skill" tabindex="-1">Step 2: Use the /build-component skill <a class="header-anchor" href="#step-2-use-the-build-component-skill" aria-label="Permalink to &quot;Step 2: Use the /build-component skill&quot;">​</a></h3><p>Paste the Figma node URL and invoke the build skill:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/build-component https://www.figma.com/design/...?node-id=123-456</span></span></code></pre></div><p>This triggers a structured process that:</p><ol><li>Fetches metadata to enumerate all variants</li><li>Fetches design context for each variant</li><li>Scans for nested component dependencies</li><li>Maps Figma variables to <code>--ai-*</code> tokens</li><li>Generates HTML, CSS, and figma-notes.md following the project&#39;s component architecture</li></ol><blockquote><p><strong>Do not use a freeform prompt.</strong> The <code>/build-component</code> skill enforces the full variant audit, token gap checks, and bottom-up dependency resolution defined in CLAUDE.md. A freeform prompt risks skipping variants or hardcoding values.</p></blockquote><h3 id="step-3-what-claude-does-internally" tabindex="-1">Step 3: What Claude does internally <a class="header-anchor" href="#step-3-what-claude-does-internally" aria-label="Permalink to &quot;Step 3: What Claude does internally&quot;">​</a></h3><p>Claude Code will call these MCP tools automatically:</p><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th></tr></thead><tbody><tr><td><code>get_design_context</code></td><td>Reads the component&#39;s layout, spacing, auto-layout settings, and fills</td></tr><tr><td><code>get_variable_defs</code></td><td>Extracts which Figma variables (tokens) are bound to each layer</td></tr><tr><td><code>get_code_connect_map</code></td><td>Checks if a code mapping already exists for this component</td></tr></tbody></table><p>Claude then maps each Figma variable to its <code>--ai-*</code> counterpart using the table in <code>CLAUDE.md</code>, and generates the component files.</p><h3 id="step-4-review-and-test-locally" tabindex="-1">Step 4: Review and test locally <a class="header-anchor" href="#step-4-review-and-test-locally" aria-label="Permalink to &quot;Step 4: Review and test locally&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # opens localhost with hot reload</span></span></code></pre></div><p>Open <code>src/components/&lt;Name&gt;/&lt;Name&gt;.html</code> to see the standalone component demo.</p><hr><h2 id="part-2-code-→-figma-prototypes" tabindex="-1">Part 2: Code → Figma (Prototypes) <a class="header-anchor" href="#part-2-code-→-figma-prototypes" aria-label="Permalink to &quot;Part 2: Code → Figma (Prototypes)&quot;">​</a></h2><p>The Code → Figma direction is for <strong>prototypes</strong> — new screens or flows built from code using existing components and tokens. This is <strong>not</strong> for pushing back a component that was already built from Figma (that would be pointless — it already exists there).</p><h3 id="when-to-use-this" tabindex="-1">When to use this <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to use this&quot;">​</a></h3><ul><li>Exploring a new UI flow (e.g. registration, settings, onboarding)</li><li>Building a screen layout that doesn&#39;t exist in Figma yet</li><li>Creating a quick visual for designer review</li></ul><h3 id="step-1-build-the-prototype-with-build-prototype" tabindex="-1">Step 1: Build the prototype with /build-prototype <a class="header-anchor" href="#step-1-build-the-prototype-with-build-prototype" aria-label="Permalink to &quot;Step 1: Build the prototype with /build-prototype&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/build-prototype Two-step registration flow with email/password then profile details</span></span></code></pre></div><p>Claude Code will:</p><ol><li>Plan the screens and check for existing components</li><li>Build HTML/CSS in <code>src/prototypes/&lt;Name&gt;/</code> using only <code>--ai-*</code> tokens</li><li>Capture each screen to Figma via <code>generate_figma_design</code></li><li>Push frames to the <strong>Prototypes page</strong> in the Design System file</li></ol><h3 id="step-2-designer-runs-re-tokenise-plugin" tabindex="-1">Step 2: Designer runs Re-tokenise plugin <a class="header-anchor" href="#step-2-designer-runs-re-tokenise-plugin" aria-label="Permalink to &quot;Step 2: Designer runs Re-tokenise plugin&quot;">​</a></h3><p>The captured frames arrive in Figma with <strong>raw hex values and px dimensions</strong> — the capture process cannot preserve CSS variable bindings. The designer must rebind them to Figma variables:</p><ol><li>Select the captured frame in Figma</li><li>Run <strong>Plugins → Development → Re-tokenise</strong></li><li>The plugin maps hex colours to the nearest Semantic variable, px font sizes to Typography variables, and applies the correct variable bindings</li></ol><blockquote><p><strong>Plugin location:</strong> <code>figma-plugin-retokenise/</code> in the repo. Import via Figma Desktop → Plugins → Development → Import plugin from manifest.</p></blockquote><h3 id="step-3-designer-converts-to-component" tabindex="-1">Step 3: Designer converts to component <a class="header-anchor" href="#step-3-designer-converts-to-component" aria-label="Permalink to &quot;Step 3: Designer converts to component&quot;">​</a></h3><p>Once re-tokenised, the designer:</p><ol><li>Reviews the frame and adjusts any missed bindings</li><li>Converts it to a Figma component (if it should become reusable)</li><li>Adds to the appropriate page in the Design System or AI Chat file</li><li>Sets up variants, auto-layout, and constraints</li></ol><h3 id="the-loop" tabindex="-1">The loop <a class="header-anchor" href="#the-loop" aria-label="Permalink to &quot;The loop&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Developer describes flow</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  /build-prototype</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Code (src/prototypes/) → captured to Figma (Prototypes page)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  Designer runs Re-tokenise plugin</span></span>
<span class="line"><span>  │  Designer converts to component</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Figma component (ready for production)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  /build-component (if needed as production code)</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Code (src/components/ or src/patterns/)</span></span></code></pre></div><hr><h2 id="part-3-qa-—-reviewing-components" tabindex="-1">Part 3: QA — Reviewing Components <a class="header-anchor" href="#part-3-qa-—-reviewing-components" aria-label="Permalink to &quot;Part 3: QA — Reviewing Components&quot;">​</a></h2><h3 id="why-review" tabindex="-1">Why review? <a class="header-anchor" href="#why-review" aria-label="Permalink to &quot;Why review?&quot;">​</a></h3><p>Tokens change. The designer updates a colour, spacing value, or adds a new variant. Components built weeks ago may now be using outdated values — but nothing breaks visually until someone compares against Figma. The <code>/review-component</code> skill automates this comparison.</p><h3 id="when-to-use-this-1" tabindex="-1">When to use this <a class="header-anchor" href="#when-to-use-this-1" aria-label="Permalink to &quot;When to use this&quot;">​</a></h3><ul><li><strong>After a token migration</strong> — bulk-check all components against updated Figma values</li><li><strong>After a designer updates components</strong> — verify code matches the new Figma state</li><li><strong>Before a release</strong> — QA pass to catch any token drift</li><li><strong>When something looks &quot;off&quot;</strong> — compare a specific component against its Figma source</li></ul><h3 id="how-to-use-it" tabindex="-1">How to use it <a class="header-anchor" href="#how-to-use-it" aria-label="Permalink to &quot;How to use it&quot;">​</a></h3><p>Paste the Figma component set URL:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/review-component https://www.figma.com/design/...?node-id=123-456</span></span></code></pre></div><p>Claude Code will:</p><ol><li><strong>Map the component tree</strong> — fetch metadata to identify all variants and nested dependencies</li><li><strong>Check each component against the codebase</strong> — verify it exists in <code>src/components/</code> or <code>src/patterns/</code></li><li><strong>Audit every variant</strong> — fetch <code>get_design_context</code> for each state/size/device variant</li><li><strong>Compare tokens</strong> — flag any mismatch between Figma token values and the CSS</li><li><strong>Check for token drift</strong> — cross-reference component CSS against current generated tokens</li><li><strong>Flag contextual overrides</strong> — identify where a parent uses a child differently from the child&#39;s base design</li><li><strong>Present a build plan</strong> — summary table showing each component as Current, Outdated, or Missing</li></ol><h3 id="what-it-checks" tabindex="-1">What it checks <a class="header-anchor" href="#what-it-checks" aria-label="Permalink to &quot;What it checks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Check</th><th>Example issue</th></tr></thead><tbody><tr><td>Token mismatch</td><td>CSS uses <code>--ai-surface-minimal</code> but Figma shows <code>--ai-surface-contrast</code></td></tr><tr><td>Missing variant</td><td>Figma has a Hover state that CSS doesn&#39;t implement</td></tr><tr><td>Stale token</td><td>Component uses <code>--ai-chat-surface-primary</code> (removed) instead of <code>--ai-surface-primary</code></td></tr><tr><td>Wrong value</td><td><code>border-radius: --ai-radius-sm</code> but Figma shows <code>--ai-radius-md</code></td></tr><tr><td>Font drift</td><td>CSS uses <code>--ai-font-body</code> where Figma style is <code>title/*</code></td></tr><tr><td>Hardcoded value</td><td>CSS has a hex colour that should be a token</td></tr></tbody></table><h3 id="the-output" tabindex="-1">The output <a class="header-anchor" href="#the-output" aria-label="Permalink to &quot;The output&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Component       | Status      | Action</span></span>
<span class="line"><span>----------------|-------------|------------------------------------------</span></span>
<span class="line"><span>SuggestedQuestion | ✓ Current  | No action needed</span></span>
<span class="line"><span>SourcesLink     | ⚠ Outdated  | Link variant bg: surface-minimal → surface-contrast</span></span>
<span class="line"><span>ChatHeader      | ⚠ Outdated  | Dropdown bg: surface-primary → surface-secondary</span></span>
<span class="line"><span>MessageInput    | ✓ Current  | No action needed</span></span></code></pre></div><p>You then approve the plan and Claude applies only the listed fixes — no unnecessary rewrites.</p><h3 id="batch-review" tabindex="-1">Batch review <a class="header-anchor" href="#batch-review" aria-label="Permalink to &quot;Batch review&quot;">​</a></h3><p>To review multiple components at once, provide several Figma URLs:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/review-component https://figma.com/...?node-id=A https://figma.com/...?node-id=B https://figma.com/...?node-id=C</span></span></code></pre></div><p>Or review an entire composed component — <code>/review-component</code> automatically walks the full dependency tree, so reviewing a template like AiChat will audit every nested child.</p><hr><h2 id="part-4-token-updates" tabindex="-1">Part 4: Token Updates <a class="header-anchor" href="#part-4-token-updates" aria-label="Permalink to &quot;Part 4: Token Updates&quot;">​</a></h2><h3 id="how-the-token-pipeline-works" tabindex="-1">How the token pipeline works <a class="header-anchor" href="#how-the-token-pipeline-works" aria-label="Permalink to &quot;How the token pipeline works&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FIGMA</span></span>
<span class="line"><span>  ├── Design System library (Primitives, Scale, Semantic Light/Dark, Typography)</span></span>
<span class="line"><span>  └── AI Chat file (Semantic Chat Light/Chat Dark)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  Designer exports variables as DTCG JSON</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>FigmaTokens/          ← JSON files (source of truth, never edit manually)</span></span>
<span class="line"><span>  ├── Primitive.tokens.json</span></span>
<span class="line"><span>  ├── Scale/Scale.tokens.json</span></span>
<span class="line"><span>  ├── Semantic/</span></span>
<span class="line"><span>  │   ├── Light.tokens.json       (from Design System library)</span></span>
<span class="line"><span>  │   ├── Dark.tokens.json        (from Design System library)</span></span>
<span class="line"><span>  │   ├── ChatLight.tokens.json   (from AI Chat file)</span></span>
<span class="line"><span>  │   └── ChatDark.tokens.json    (from AI Chat file)</span></span>
<span class="line"><span>  └── Typography/</span></span>
<span class="line"><span>      ├── Desktop.tokens.json</span></span>
<span class="line"><span>      ├── Mobile.tokens.json</span></span>
<span class="line"><span>      └── Minimised.tokens.json</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  npm run tokens</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>css/</span></span>
<span class="line"><span>  ├── tokens.css              ← :root (light)</span></span>
<span class="line"><span>  ├── tokens-dark.css         ← [data-theme=&quot;dark&quot;]</span></span>
<span class="line"><span>  ├── tokens-chat.css         ← [data-surface=&quot;chat&quot;]</span></span>
<span class="line"><span>  ├── tokens-chat-dark.css    ← [data-theme=&quot;dark&quot;] [data-surface=&quot;chat&quot;]</span></span>
<span class="line"><span>  ├── tokens-mobile.css       ← @media (max-width: 639px)</span></span>
<span class="line"><span>  └── tokens-minimised.css    ← [data-layout=&quot;minimised&quot;]</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  │  All components reference --ai-* variables automatically</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Browser / Build</span></span></code></pre></div><hr><h3 id="one-time-setup-set-code-syntax-for-each-variable-in-figma" tabindex="-1">One-time setup: Set Code Syntax for each variable in Figma <a class="header-anchor" href="#one-time-setup-set-code-syntax-for-each-variable-in-figma" aria-label="Permalink to &quot;One-time setup: Set Code Syntax for each variable in Figma&quot;">​</a></h3><p>Each Figma variable must have its <strong>Web code syntax</strong> set. This is what determines the CSS variable name in the exported JSON (<code>com.figma.codeSyntax.WEB</code>) and ultimately in <code>css/tokens.css</code>.</p><ol><li>Open the Figma file</li><li>Open the <strong>Variables</strong> panel: right-click the canvas → Variables, or use the local variables button in the top toolbar</li><li>Select a variable collection (e.g. &quot;Light&quot;)</li><li>Click the <strong>&quot;&lt;&gt;&quot;</strong> (Code) button or the <strong>Code syntax</strong> option in the panel header</li><li>For each variable, set the <strong>Web</strong> field to the <code>--ai-*</code> name (e.g. <code>--ai-surface-primary</code>)</li></ol><p>This only needs to be done once per variable. New variables added later must have their Web code syntax set before exporting, or they will be silently omitted from <code>css/tokens.css</code>.</p><blockquote><p><strong>Rule:</strong> Style Dictionary only outputs variables that have <code>com.figma.codeSyntax.WEB</code> set. Any variable without a Web code syntax will be skipped by <code>npm run tokens</code>.</p></blockquote><hr><h3 id="exporting-variables-from-figma-do-this-after-every-token-change" tabindex="-1">Exporting variables from Figma (do this after every token change) <a class="header-anchor" href="#exporting-variables-from-figma-do-this-after-every-token-change" aria-label="Permalink to &quot;Exporting variables from Figma (do this after every token change)&quot;">​</a></h3><p>Figma Professional includes a <strong>native Variables export</strong> — no third-party plugin is needed. The export produces DTCG JSON with Figma&#39;s proprietary extensions (<code>com.figma.variableId</code>, <code>com.figma.codeSyntax</code>, etc.), which is exactly the format <code>style-dictionary.config.mjs</code> expects.</p><p><strong>Steps:</strong></p><ol><li><p>Open the Figma file</p></li><li><p>Open the <strong>Variables</strong> panel (same as above)</p></li><li><p>Click the <strong>export icon</strong> (↓ download) at the top-right of the Variables panel — Figma downloads a <code>.zip</code> file</p></li><li><p>Unzip it — you&#39;ll find JSON files named after each variable collection</p></li><li><p><strong>Replace</strong> the matching files in <code>FigmaTokens/</code>:</p><p><strong>From the Design System library:</strong></p><table tabindex="0"><thead><tr><th>Figma collection</th><th>File in repo</th></tr></thead><tbody><tr><td>Primitives</td><td><code>FigmaTokens/Primitive.tokens.json</code></td></tr><tr><td>Scale</td><td><code>FigmaTokens/Scale/Scale.tokens.json</code></td></tr><tr><td>Semantic (Light mode)</td><td><code>FigmaTokens/Semantic/Light.tokens.json</code></td></tr><tr><td>Semantic (Dark mode)</td><td><code>FigmaTokens/Semantic/Dark.tokens.json</code></td></tr><tr><td>Typography (Desktop)</td><td><code>FigmaTokens/Typography/Desktop.tokens.json</code></td></tr><tr><td>Typography (Mobile)</td><td><code>FigmaTokens/Typography/Mobile.tokens.json</code></td></tr><tr><td>Typography (Minimised)</td><td><code>FigmaTokens/Typography/Minimised.tokens.json</code></td></tr></tbody></table><p><strong>From the AI Chat file:</strong></p><table tabindex="0"><thead><tr><th>Figma collection</th><th>File in repo</th></tr></thead><tbody><tr><td>Semantic (Chat Light mode)</td><td><code>FigmaTokens/Semantic/ChatLight.tokens.json</code></td></tr><tr><td>Semantic (Chat Dark mode)</td><td><code>FigmaTokens/Semantic/ChatDark.tokens.json</code></td></tr></tbody></table></li><li><p>Run the pipeline:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tokens</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # rebuilds css/tokens.css from FigmaTokens/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # verify changes in the browser</span></span></code></pre></div></li></ol><blockquote><p><strong>Never edit <code>FigmaTokens/*.json</code> manually.</strong> They are the source of truth from Figma. If you need to correct a value, change it in Figma and re-export.</p></blockquote><hr><h3 id="when-a-designer-changes-a-token-value" tabindex="-1">When a designer changes a token value <a class="header-anchor" href="#when-a-designer-changes-a-token-value" aria-label="Permalink to &quot;When a designer changes a token value&quot;">​</a></h3><ol><li>Designer updates the variable in Figma&#39;s Variables panel</li><li>Designer exports → replaces file(s) in <code>FigmaTokens/</code></li><li>Run <code>npm run tokens</code> — <code>css/tokens.css</code> regenerates automatically</li><li>All components update automatically (no code changes needed)</li><li>Update <code>CLAUDE.md</code> Section 2 or 3 with the new value if it changed</li></ol><h3 id="when-a-new-token-is-added-in-figma" tabindex="-1">When a new token is added in Figma <a class="header-anchor" href="#when-a-new-token-is-added-in-figma" aria-label="Permalink to &quot;When a new token is added in Figma&quot;">​</a></h3><p>Same flow as above, plus:</p><ul><li>Ensure the new variable has <strong>Web code syntax</strong> set in Figma (see above)</li><li>Update the tables in <code>CLAUDE.md</code> Sections 2–3 with the new <code>--ai-*</code> variable</li></ul><hr><h3 id="why-you-can-t-automate-the-export-via-rest-api" tabindex="-1">Why you can&#39;t automate the export via REST API <a class="header-anchor" href="#why-you-can-t-automate-the-export-via-rest-api" aria-label="Permalink to &quot;Why you can&#39;t automate the export via REST API&quot;">​</a></h3><p>Figma&#39;s REST API (<code>GET /v1/files/:fileKey/variables</code>) requires the <code>file_variables:read</code> OAuth scope. This scope is <strong>only available on Figma Organization and Enterprise plans</strong> — it does not appear in the token generator on Professional plan.</p><p>The native Variables panel export described above is the correct approach for Professional plan.</p><p>To automate in the future: upgrade to Figma Org/Enterprise, create a personal access token with <code>file_variables:read</code> scope, then use the API to download and write the JSON files directly to <code>FigmaTokens/</code>.</p><hr><blockquote><p><strong>Team setup and troubleshooting:</strong> See the <a href="/figmaTest/docs/team-setup.html">Team Setup</a> page.</p></blockquote>`,91)])])}const u=a(o,[["render",i]]);export{g as __pageData,u as default};
